const TOOLS = {
  pexels: { title: 'Clip Downloader — Pexels & Pixabay', base64: TOOLS_DATA.pexels },
  workflow: { title: 'Flujo de Trabajo (En desarrollo)', base64: TOOLS_DATA.workflow },
  freepik: { title: 'Generador de Imágenes', base64: TOOLS_DATA.freepik },
  videosync: { title: 'VideoSync Editor', base64: TOOLS_DATA.videosync }
};

window.openTool = function(toolId) {
  if (!currentUser) {
    showAuth();
    return;
  }
  const tool = TOOLS[toolId];
  if (!tool) return;
  const overlay = document.getElementById('toolOverlay');
  const iframe = document.getElementById('toolIframe');
  const title = document.getElementById('toolOverlayTitle');
  title.textContent = tool.title;
  
  const binaryStr = window.atob(tool.base64);
  const bytes = new Uint8Array(binaryStr.length);
  for (let i = 0; i < binaryStr.length; i++) {
      bytes[i] = binaryStr.charCodeAt(i);
  }
  iframe.removeAttribute('src');
  iframe.srcdoc = new TextDecoder('utf-8').decode(bytes);

  overlay.classList.add('active');
  document.body.style.overflow = 'hidden';
};

window.closeTool = function() {
  const overlay = document.getElementById('toolOverlay');
  const iframe = document.getElementById('toolIframe');
  overlay.classList.remove('active');
  document.body.style.overflow = '';
  setTimeout(() => { iframe.src = ''; }, 300);
};
