window.markProjectDone = async function(id) {
  if(typeof firebaseReady !== 'undefined' && firebaseReady) {
    try {
      await db.collection('project_messages').doc(id).update({ status: 'realizado' });
      showToast('Proyecto marcado como realizado');
    } catch(e) { showToast('Error al actualizar'); }
  } else {
    let hw = JSON.parse(localStorage.getItem('tierlist_projects') || '[]');
    const idx = hw.findIndex(m => m.id === id);
    if(idx !== -1) {
      hw[idx].status = 'realizado';
      localStorage.setItem('tierlist_projects', JSON.stringify(hw));
    }
    showToast('Proyecto marcado como realizado (Local)');
    loadProjectMessages();
  }
};

