window.deleteProjectMessage = async function(id) {
  if(!confirm('Ã‚Â¿Seguro que deseas borrar este mensaje?')) return;
  if(typeof firebaseReady !== 'undefined' && firebaseReady) {
    try {
      await db.collection('project_messages').doc(id).delete();
      showToast('Mensaje borrado');
      loadProjectMessages();
    } catch(e) { showToast('Error al borrar'); }
  } else {
    let hw = JSON.parse(localStorage.getItem('tierlist_projects') || '[]');
    hw = hw.filter(m => m.id !== id);
    localStorage.setItem('tierlist_projects', JSON.stringify(hw));
    showToast('Mensaje borrado (Local)');
    loadProjectMessages();
  }
};

