// ========================================
// AGENDA / BOARD - Sticky Notes Calendar
// ========================================

const MONTH_NAMES_AGENDA = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
let agendaMonth = new Date().getMonth();
let agendaYear = new Date().getFullYear();
let agendaNotes = [];
let agendaNotesListener = null;

function renderAgenda() {
  const grid = document.getElementById('agendaGrid');
  const label = document.getElementById('agendaMonthLabel');
  if (!grid || !label) return;
  
  label.textContent = `${MONTH_NAMES_AGENDA[agendaMonth]} ${agendaYear}`;
  
  // First day of month (0=Sun, convert to Mon=0)
  const firstDay = new Date(agendaYear, agendaMonth, 1).getDay();
  const startOffset = (firstDay === 0 ? 6 : firstDay - 1); // Monday-based
  const daysInMonth = new Date(agendaYear, agendaMonth + 1, 0).getDate();
  const daysInPrevMonth = new Date(agendaYear, agendaMonth, 0).getDate();
  
  const today = new Date();
  const isCurrentMonth = (today.getMonth() === agendaMonth && today.getFullYear() === agendaYear);
  const todayDate = today.getDate();
  
  let html = '';
  
  // Previous month days
  for (let i = startOffset - 1; i >= 0; i--) {
    const d = daysInPrevMonth - i;
    html += `<div class="agenda-day other-month"><span class="agenda-day-number">${d}</span></div>`;
  }
  
  // Current month days
  for (let d = 1; d <= daysInMonth; d++) {
    const isToday = isCurrentMonth && d === todayDate;
    const dayNotes = agendaNotes.filter(n => n.day === d);
    
    let notesHtml = '';
    const maxVisible = 3;
    dayNotes.slice(0, maxVisible).forEach(note => {
      notesHtml += `<div class="sticky-note sticky-note-${note.color || 'yellow'}" data-note-id="${note.id}" onclick="event.stopPropagation(); openAgendaNoteModal(${d}, '${note.id}')">
        <div class="sticky-note-text">${escapeHTML(note.text)}</div>
      </div>`;
    });
    if (dayNotes.length > maxVisible) {
      notesHtml += `<div class="sticky-more">+${dayNotes.length - maxVisible} más</div>`;
    }
    
    html += `<div class="agenda-day${isToday ? ' is-today' : ''}" onclick="openAgendaNoteModal(${d})">
      <span class="agenda-day-number">${d}</span>
      <div class="agenda-day-notes">${notesHtml}</div>
      <div class="agenda-day-add"><span class="material-symbols-rounded">add</span>Nota</div>
    </div>`;
  }
  
  // Next month fill
  const totalCells = startOffset + daysInMonth;
  const remaining = (7 - (totalCells % 7)) % 7;
  for (let d = 1; d <= remaining; d++) {
    html += `<div class="agenda-day other-month"><span class="agenda-day-number">${d}</span></div>`;
  }
  
  grid.innerHTML = html;
  
  // Load notes from Firestore
  loadAgendaNotes();
}

function escapeHTML(str) {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

function loadAgendaNotes() {
  if (!currentUser) return;
  
  // Unsubscribe previous listener
  if (agendaNotesListener) { agendaNotesListener(); agendaNotesListener = null; }
  
  const monthKey = `${agendaYear}-${String(agendaMonth + 1).padStart(2, '0')}`;
  
  agendaNotesListener = db.collection('users').doc(currentUser.uid)
    .collection('agendaNotes')
    .where('monthKey', '==', monthKey)
    .orderBy('createdAt', 'asc')
    .onSnapshot(snapshot => {
      agendaNotes = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      refreshAgendaGrid();
    }, err => {
      console.error('Error loading agenda notes:', err);
      // Fallback: try without ordering if index is missing
      db.collection('users').doc(currentUser.uid)
        .collection('agendaNotes')
        .where('monthKey', '==', monthKey)
        .get().then(snapshot => {
          agendaNotes = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
          refreshAgendaGrid();
        });
    });
}

function refreshAgendaGrid() {
  const grid = document.getElementById('agendaGrid');
  if (!grid) return;
  
  const dayCells = grid.querySelectorAll('.agenda-day:not(.other-month)');
  dayCells.forEach(cell => {
    const numEl = cell.querySelector('.agenda-day-number');
    if (!numEl) return;
    const d = parseInt(numEl.textContent);
    const dayNotes = agendaNotes.filter(n => n.day === d);
    const notesContainer = cell.querySelector('.agenda-day-notes');
    if (!notesContainer) return;
    
    let notesHtml = '';
    const maxVisible = 3;
    dayNotes.slice(0, maxVisible).forEach(note => {
      notesHtml += `<div class="sticky-note sticky-note-${note.color || 'yellow'}" data-note-id="${note.id}" onclick="event.stopPropagation(); openAgendaNoteModal(${d}, '${note.id}')">
        <div class="sticky-note-text">${escapeHTML(note.text)}</div>
      </div>`;
    });
    if (dayNotes.length > maxVisible) {
      notesHtml += `<div class="sticky-more">+${dayNotes.length - maxVisible} más</div>`;
    }
    notesContainer.innerHTML = notesHtml;
  });
}

function openAgendaNoteModal(day, noteId) {
  const modal = document.getElementById('agendaNoteModal');
  const titleEl = document.getElementById('agendaNoteModalTitle');
  const textEl = document.getElementById('agendaNoteText');
  const idEl = document.getElementById('agendaNoteId');
  const dayEl = document.getElementById('agendaNoteDay');
  const deleteBtn = document.getElementById('deleteAgendaNoteBtn');
  const colorBtns = document.querySelectorAll('.agenda-color-btn');
  
  dayEl.value = day;
  
  if (noteId) {
    // Edit existing note
    const note = agendaNotes.find(n => n.id === noteId);
    if (!note) return;
    titleEl.textContent = `Editar Nota - ${day} ${MONTH_NAMES_AGENDA[agendaMonth]}`;
    textEl.value = note.text;
    idEl.value = noteId;
    deleteBtn.style.display = '';
    // Set active color
    colorBtns.forEach(btn => {
      btn.classList.toggle('active', btn.dataset.color === (note.color || 'yellow'));
    });
  } else {
    // New note
    titleEl.textContent = `Nueva Nota - ${day} ${MONTH_NAMES_AGENDA[agendaMonth]}`;
    textEl.value = '';
    idEl.value = '';
    deleteBtn.style.display = 'none';
    colorBtns.forEach(btn => {
      btn.classList.toggle('active', btn.dataset.color === 'yellow');
    });
  }
  
  modal.classList.add('active');
  setTimeout(() => textEl.focus(), 200);
}

function closeAgendaNoteModal() {
  document.getElementById('agendaNoteModal').classList.remove('active');
}

// Color picker
document.getElementById('agendaColorPicker')?.addEventListener('click', e => {
  const btn = e.target.closest('.agenda-color-btn');
  if (!btn) return;
  document.querySelectorAll('.agenda-color-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
});

// Close modal
document.getElementById('closeAgendaNoteModalBtn')?.addEventListener('click', closeAgendaNoteModal);
document.getElementById('agendaNoteModal')?.addEventListener('click', e => {
  if (e.target === e.currentTarget) closeAgendaNoteModal();
});

// Save note
document.getElementById('agendaNoteForm')?.addEventListener('submit', async (e) => {
  e.preventDefault();
  if (!currentUser) { showToast('Inicia sesión primero'); return; }
  
  const text = document.getElementById('agendaNoteText').value.trim();
  const day = parseInt(document.getElementById('agendaNoteDay').value);
  const noteId = document.getElementById('agendaNoteId').value;
  const activeColor = document.querySelector('.agenda-color-btn.active');
  const color = activeColor ? activeColor.dataset.color : 'yellow';
  
  if (!text) return;
  
  const monthKey = `${agendaYear}-${String(agendaMonth + 1).padStart(2, '0')}`;
  
  const noteData = {
    text,
    day,
    month: agendaMonth,
    year: agendaYear,
    monthKey,
    color,
    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
  };
  
  try {
    const notesRef = db.collection('users').doc(currentUser.uid).collection('agendaNotes');
    if (noteId) {
      await notesRef.doc(noteId).update(noteData);
      showToast('Nota actualizada');
    } else {
      noteData.createdAt = firebase.firestore.FieldValue.serverTimestamp();
      await notesRef.add(noteData);
      showToast('Nota creada');
    }
    closeAgendaNoteModal();
  } catch (err) {
    console.error('Error saving note:', err);
    showToast('Error al guardar la nota');
  }
});

// Delete note
document.getElementById('deleteAgendaNoteBtn')?.addEventListener('click', async () => {
  const noteId = document.getElementById('agendaNoteId').value;
  if (!noteId || !currentUser) return;
  
  if (!confirm('¿Eliminar esta nota?')) return;
  
  try {
    await db.collection('users').doc(currentUser.uid).collection('agendaNotes').doc(noteId).delete();
    showToast('Nota eliminada');
    closeAgendaNoteModal();
  } catch (err) {
    console.error('Error deleting note:', err);
    showToast('Error al eliminar');
  }
});

// Navigation arrows
document.getElementById('agendaPrev')?.addEventListener('click', () => {
  agendaMonth--;
  if (agendaMonth < 0) { agendaMonth = 11; agendaYear--; }
  renderAgenda();
});

document.getElementById('agendaNext')?.addEventListener('click', () => {
  agendaMonth++;
  if (agendaMonth > 11) { agendaMonth = 0; agendaYear++; }
  renderAgenda();
});

document.getElementById('agendaToday')?.addEventListener('click', () => {
  const now = new Date();
  agendaMonth = now.getMonth();
  agendaYear = now.getFullYear();
  renderAgenda();
});


